  backlog: 'Backlog',
  todo: 'Todo',
  in_progress: 'In Progress',
  review: 'Review',
  done: 'Done',
}

const TASK_THEME: Record<string, { lane: string; badge: string; empty: string }> = {
  backlog: {
    lane: 'border-[#f0d4bf] bg-[#fff4ea]',
    badge: 'bg-[#ffd8b8] text-[#9b5824]',
    empty: 'text-[#ad7b56] border-[#efc8a6] bg-[#fff0e0]',
  },
  todo: {
